content.newText:
$ErrorActionPreference = "Stop"
$ProgressPreference = "SilentlyContinue"

# 认证信息
$authInfo = "mail_ricklee:aileen007~"
$authBytes = [System.Text.Encoding]::ASCII.GetBytes($authInfo)
$authHeader = [Convert]::ToBase64String($authBytes)
$headers = @{
    Authorization = 'Basic ' + $authHeader
    ContentType = 'application/json'
}

# 获取当前页面
$uri = "http://192.168.10.198:8090/rest/api/content/131040932?expand=body.storage,version"
$current = Invoke-RestMethod -Uri $uri -Headers $headers -Method Get

$currentVersion = $current.version.number
Write-Host "Current version: $currentVersion"

$fullHtml = $current.body.storage.value

# 新内容
$newContent = '<p><strong>my-test-skills</strong></p><p>Reference: logistics-service\src\main\java\com\zhengding\cloud\logistics\service\impl\ExpressRuleProductPrototypeBasicServiceImpl.java #L48-L54</p><p>Task: create mylist method with queryWrapper</p>'

# 使用正则表达式找到李淼的行
$pattern = '(<tr>.*?<td rowspan="3"><span>)\u674e\u6dfc(</span></td>.*?</tr>)'
$match = [regex]::Match($fullHtml, $pattern, [System.Text.RegularExpressions.RegexOptions]::Singleline)

if (-not $match.Success) {
    Write-Host "Li Miao row not found"
    exit 1
}

$liMiaoRow = $match.Value
Write-Host "Found Li Miao row, length: $($liMiaoRow.Length)"

# 在李淼行中找到'三'列之后的第一个空 td（即'四'列）
# 结构：...列三</td><td colspan="1"><br /></td><td colspan="1"><br /></td>...
# '四'列是列三之后的第一个 <td colspan="1"><br /></td>

# 找到列三的内容结束位置
$col3EndPattern = '</td><td colspan="1"><p>今日计划</p>'
$col3Match = [regex]::Match($liMiaoRow, $col3EndPattern)

if ($col3Match.Success) {
    Write-Host "Found column 3 end"
    # 列三之后有两个空 td，第一个是'四'，第二个是'五'
    $afterCol3 = $liMiaoRow.Substring($col3Match.Index + $col3Match.Length)

    # 找到第一个空 td
    $emptyTdPattern = '<td colspan="1"><br /></td>'
    $emptyTdMatch = [regex]::Match($afterCol3, $emptyTdPattern)

    if ($emptyTdMatch.Success) {
        $siColumnInRow = $emptyTdMatch.Index
        Write-Host "Found column 4 in row at position: $siColumnInRow"

        # 计算在整个 HTML 中的位置
        $siColumnPos = $match.Index + $col3Match.Index + $col3Match.Length + $siColumnInRow

        # 替换
        $newHtml = $fullHtml.Substring(0, $siColumnPos) + $newContent + $fullHtml.Substring($siColumnPos + $emptyTdPattern.Length)

        Write-Host "Content replaced"
    } else {
        Write-Host "Empty td not found in row"
        exit 1
    }
} else {
    Write-Host "Column 3 end not found, trying alternative approach"

    # Alternative: find all td tags in Li Miao row and replace the 6th one (index 5, counting from 0)
    $tdMatches = [regex]::Matches($liMiaoRow, '<td[^>]*>.*?</td>', [System.Text.RegularExpressions.RegexOptions]::Singleline)
    Write-Host "Found $($tdMatches.Count) td tags in row"

    # td 索引：0=姓名，1=周计划，2=标题，3=列一，4=列二，5=列三，6=列四，7=列五
    if ($tdMatches.Count -ge 7) {
        $targetTd = $tdMatches[6]  # 列四
        Write-Host "Found target td at position: $($targetTd.Index)"

        $siColumnPos = $match.Index + $targetTd.Index
        $newHtml = $fullHtml.Substring(0, $siColumnPos) + $newContent + $fullHtml.Substring($siColumnPos + $targetTd.Length)
        Write-Host "Content replaced using alternative approach"
    } else {
        Write-Host "Not enough td tags found"
        exit 1
    }
}

# 构建更新请求
$newVersion = $currentVersion + 1
$bodyObj = @{
    id = "131040932"
    type = "page"
    status = "current"
    version = @{ number = $newVersion }
    body = @{
        storage = @{
            value = $newHtml
            representation = "storage"
        }
    }
}

$bodyJson = $bodyObj | ConvertTo-Json -Depth 10 -Compress

Write-Host "Updating to version: $newVersion"

# 发送更新请求
try {
    $response = Invoke-RestMethod -Uri "http://192.168.10.198:8090/rest/api/content/131040932" -Headers $headers -Method Put -Body $bodyJson
    Write-Host "Success! New version: $($response.version.number)"
} catch {
    Write-Host "Error: $($_.Exception.Message)"
    if ($_.ErrorDetails.Message) {
        Write-Host "Response: $($_.ErrorDetails.Message)"
    }
}

